#include <iostream>
#include <cmath>
#include <cstdio>

using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    long long n;
    cin >> n;

    // The expression sqrt(2 + sqrt(2 + sqrt(2 + ...))) converges very quickly to 2.
    // If n is large enough, the value is essentially 2 for the required precision.
    // We need to compute accurately enough for n up to maybe 30-40 iterations.
    // For larger n, the value converges to 2 within double precision.

    // Compute from the innermost: start with x = 0, then for i from 1 to n:
    // x = sqrt(2 + x)
    // But n can be up to 1e9, so we cannot iterate that many times.
    // Observe that for n >= 30, the value is 2.0 within double precision.

    long long max_iter = min(n, 60LL);
    double x = 0.0;
    for (long long i = 0; i < max_iter; ++i) {
        x = sqrt(2.0 + x);
    }

    // For n up to 1e9, if max_iter < n, the result is essentially 2.0
    // But we already computed up to 60 iterations which gives ~2.0.

    printf("%.9f\n", x);
    return 0;
}
